import axios from 'axios';
import { useState, useEffect } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const authUrl = `https://example.com/oauth/authorize?response_type=token&client_id=${clientId}&redirect_uri=http://localhost:3000/callback`;

function Login() {
  const [loginError, setLoginError] = useState(null);
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    if (window.location.hash) {
      const hashParams = getHashParams();
      setAccessToken(hashParams.access_token);
    }
  }, []);

  const getHashParams = () => {
    const params = {};
    const hash = window.location.hash.substring(1).split('&');
    for (let i = 0; i < hash.length; i++) {
      const [key, value] = hash[i].split('=');
      params[key] = value;
    }
    return params;
  };

  const handleLogin = () => {
    window.location.href = authUrl;
  };

  if (accessToken) {
    // Use the access token to make API calls
    axios.get('https://example.com/api/protected', {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    })
    .then(response => console.log(response.data))
    .catch(error => setLoginError(error.message));
  }

  return (
    <div>
      {loginError && <p style={{ color: 'red' }}>{loginError}</p>}
      {!accessToken && <button onClick={handleLogin}>Login</button>}
      {accessToken && <p>Logged in with access token: {accessToken}</p>}
    </div>
  );
}

